 3	export class ApiError extends Error {
 4	  readonly status: number
 5	  readonly detail: string | undefined
 6	
 7	  constructor(status: number, message: string, detail?: string) {
 8	    super(message)
 9	    this.name = 'ApiError'
10	    this.status = status
11	    this.detail = detail
12	  }
13	}
