15	export async function postMove(fen: string): Promise<MoveResponse> {
16	  let res: Response
17	  try {
18	    res = await fetch('/move', {
19	      method: 'POST',
20	      headers: { 'Content-Type': 'application/json' },
21	      body: JSON.stringify({ fen }),
22	    })
23	  } catch (cause) {
24	    throw new ApiError(0, 'network error', String(cause))
25	  }
26	
27	  if (!res.ok) {
28	    let detail: string | undefined
29	    try {
30	      const body = (await res.json()) as { detail?: unknown }
31	      if (typeof body.detail === 'string') detail = body.detail
32	    } catch {
33	      // body was not JSON; leave detail undefined
34	    }
35	    throw new ApiError(res.status, `POST /move failed (${res.status})`, detail)
36	  }
37	
38	  return (await res.json()) as MoveResponse
39	}
